import {AfterViewInit, ChangeDetectionStrategy, ChangeDetectorRef, Component, OnInit} from '@angular/core';

declare var Typed: any;
declare var particlesJS : any;
declare var data : any;

@Component({
    selector: 'app-home',
    templateUrl: './home.component.html',
    changeDetection: ChangeDetectionStrategy.OnPush,
    styleUrls: ['./home.component.css'],
    standalone: false
})

export class HomeComponent implements OnInit,AfterViewInit {
	public homeData = data['Home'];

	constructor(private changeDetectorRef: ChangeDetectorRef) {
		changeDetectorRef.detach();
	}
	ngOnInit(): void {
		particlesJS.load('particles-js');
		this.changeDetectorRef.detectChanges();
	}
	ngAfterViewInit() {
		new Typed("#element",{stringsElement:'#typed-strings',typeSpeed: 100,backDelay: 3000,loop:true});
	}
}
<section class="bg-home" id="home">
    <div class="bg-overlay"></div>
    <div id="particles-js"></div>
    <div class="home-center">
        <div class="home-desc-center">
            <div class="container">
                <div class="row justify-content-center">
                    <div class="col-lg-10 mt-5">
                        <div class="home-title text-center">
                            <div class="wow fadeInDownBig text-white-50 mb-3 font-weight-normal h5"
                                 data-wow-delay="0.5s">Engineering Manager
                            </div>
                            <h2 class="display-3">
                                <div id="typed-strings"><p
                                        *ngFor="let typedElement of homeData['typedElement']">{{ typedElement }} </p>
                                </div>
                                <span id="element" class="text-white"></span></h2>
                            <h3 class="wow fadeInUpBig text-light mx-auto para-desc"
                                data-wow-delay="0.5s">{{ homeData['introduction'] }}</h3></div>
                    </div>
                    <div class="mt-4 pt-2">
                        <ng-template #title><strong><em>Resume</em></strong></ng-template>
                        <div class="resume-button" placement="bottom" [ngbTooltip]="title"><a rel="noreferrer"
                                                                                              aria-label="Download Resume (opens in a new tab)"
                                                                                              target="_blank"
                                                                                              href="https://drive.google.com/file/d/{{homeData['resumeLink']}}/view?usp=sharing">
                            Download Resume <i class="fas fa-download ml-2"></i></a></div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</section>
